// BLOCK 18.1: Case Registry (Hardened v31.0)
// Creates case object for high-impact decisions
const item = $input.first();
const decision = item.json.body || item.json;

const caseObj = {
    case_id: decision.case_id || `CASE_${Date.now()}_${Math.random().toString(36).substr(2, 8)}`,
    trace_id: decision.trace_id,
    decision: decision.outcome || 'UNKNOWN',
    risk_level: decision.risk_level || 'MEDIUM',
    constitutional_basis: decision.constitutional_articles || ['Article_I'],
    appeal_status: decision.appeal_status || 'OPEN',
    created_at: new Date().toISOString(),
    __case_registered: true
};

return { json: caseObj };

// BLOCK 18.2: Tiered Access Controller (v31.0)
// Enforces different access levels per reviewer role
const item = $input.first();
const caseObj = item.json;

const ACCESS_LEVELS = {
    'CUSTOMER': { access: ['explanation'], redaction: 'FULL' },
    'BANK_COMPLIANCE': { access: ['full_transcript'], redaction: 'NONE' },
    'REGULATOR': { access: ['transcript', 'hash_chain'], redaction: 'PII_ONLY' },
    'EXTERNAL_AUDITOR': { access: ['redacted_evidence', 'seal'], redaction: 'IP_AND_PII' },
    'PUBLIC': { access: ['aggregated_metrics'], redaction: 'FULL' }
};

const reviewerRole = caseObj.requester_role || 'CUSTOMER';
const accessConfig = ACCESS_LEVELS[reviewerRole] || ACCESS_LEVELS['CUSTOMER'];

return {
    json: {
        ...caseObj,
        access_control: {
            reviewer_role: reviewerRole,
            granted_access: accessConfig.access,
            redaction_level: accessConfig.redaction
        },
        __access_configured: true
    }
};

// BLOCK 18.3: Redaction Engine (v31.0)
// Masks sensitive data before export
const item = $input.first();
const data = item.json;

let redactionLevel = data.access_control?.redaction_level || 'FULL';

const REDACTION_RULES = {
    'FULL': ['pii', 'prompt_logic', 'model_config', 'internal_notes'],
    'PII_ONLY': ['pii'],
    'IP_AND_PII': ['pii', 'prompt_logic', 'model_config'],
    'NONE': []
};

const fieldsToRedact = REDACTION_RULES[redactionLevel] || REDACTION_RULES['FULL'];

const redactedData = { ...data };
if (fieldsToRedact.includes('pii')) {
    redactedData.customer_email = '[REDACTED_PII]';
    redactedData.customer_phone = '[REDACTED_PII]';
}
if (fieldsToRedact.includes('prompt_logic')) {
    redactedData.system_prompt = '[REDACTED_IP]';
}
if (fieldsToRedact.includes('model_config')) {
    redactedData.model_parameters = '[REDACTED_IP]';
}

return {
    json: {
        ...redactedData,
        redaction_applied: fieldsToRedact,
        __redacted: true
    }
};

// BLOCK 18.5: Ombudsman Response Builder (v31.0)
const item = $input.first();
const caseObj = item.json;

return {
    json: {
        case_id: caseObj.case_id,
        status: 'REGISTERED',
        access_level: caseObj.access_control?.redaction_level,
        granted_permissions: caseObj.access_control?.granted_access,
        redacted_fields: caseObj.redaction_applied,
        review_endpoint: `/review/case/${caseObj.case_id}`,
        appeal_eligible: caseObj.appeal_status === 'OPEN',
        response_timestamp: new Date().toISOString()
    }
};

// BLOCK 19.1: Case Lookup (v31.0)
const item = $input.first();
const req = item.json.query || {};

return {
    json: {
        case_id: req.case_id,
        requester_role: req.role || 'CUSTOMER',
        __lookup_required: true
    }
};

// BLOCK 19.4: Evidence Package Builder (v31.0)
// Builds cryptographically verifiable evidence package
const crypto = require('crypto');
const item = $input.first();
const caseData = item.json;

const evidencePackage = {
    case_id: caseData.case_id,
    decision_summary: {
        outcome: caseData.decision,
        risk_level: caseData.risk_level,
        constitutional_basis: caseData.constitutional_basis
    },
    evidence_hashes: {
        data_payload_hash: crypto.createHash('sha256').update(caseData.trace_id || '').digest('hex'),
        block_chain_hash: crypto.createHash('sha256').update(caseData.case_id).digest('hex'),
        constitutional_hash: crypto.createHash('sha256').update(JSON.stringify(caseData.constitutional_basis || [])).digest('hex')
    },
    integrity_proof: {
        verifiable: true,
        algorithm: 'SHA-256'
    }
};

return {
    json: {
        ...caseData,
        evidence_package: evidencePackage,
        __package_built: true
    }
};

// BLOCK 19.5: Review Response Builder (v31.0)
const item = $input.first();
const data = item.json;

return {
    json: {
        case_id: data.case_id,
        decision: data.decision,
        risk_level: data.risk_level,
        constitutional_basis: data.constitutional_basis,
        appeal_status: data.appeal_status,
        evidence_hashes: data.evidence_package?.evidence_hashes,
        integrity_verifiable: data.evidence_package?.integrity_proof?.verifiable,
        confidence_score: 0.95,
        review_completed_at: new Date().toISOString()
    }
};

// ⚠️ BLOCK 19.ERROR: Case Not Found (v31.0)
const item = $input.first();
const req = item.json;

return {
    json: {
        error: 'CASE_NOT_FOUND',
        case_id: req.case_id,
        message: 'The requested case does not exist or access is denied.',
        timestamp: new Date().toISOString()
    }
};
